export const DEFAULT_RAMADAN_DUA_LIBRARY: RamadanDuaItem[] = BUILTIN_DUAS.map((dua) => ({
  ...dua,
  slots: [...dua.slots],
  weekdays: normalizeWeekdays(dua.weekdays)
}));

const DEFAULT_BEFORE_PRAYER_MAP = {
  fajr: 'dua_faraj',
  dhuhr: 'dua_tawassul',
  maghrib: 'dua_iftitah'
};

export const createDefaultRamadanDuaSystemSettings = (): RamadanDuaSystemSettings => ({
  enabled: true,
  autoRotate: true,
  advanceMode: 'manual',
  displayDurationSec: 12,
  fontScale: 1,
  backgroundImage: null,
  backgroundColor: '#07111f',
  mosqueMode: false,
  hideAdminControlsInMosqueMode: false,
  remoteControlMode: true,
  ramadanTheme: true,
  nightMode: true,
  autoScrollLongDuas: true,
  showReadingBar: true,
  readingBarColor: '#f6c657',
  duas: DEFAULT_RAMADAN_DUA_LIBRARY.map((dua) => ({
    ...dua,
    slots: [...dua.slots],
    weekdays: normalizeWeekdays(dua.weekdays)
  })),
  duaOrder: DEFAULT_RAMADAN_DUA_LIBRARY.map((dua) => dua.id),
  automation: {
    enabled: true,
    minutesBeforePrayer: 10,
    beforePrayerDuaByPrayer: { ...DEFAULT_BEFORE_PRAYER_MAP }
  }
});

export const normalizeRamadanDuaSystemSettings = (
  incoming?: Partial<RamadanDuaSystemSettings> | null
): RamadanDuaSystemSettings => {
  const defaults = createDefaultRamadanDuaSystemSettings();
  const incomingDuas = Array.isArray(incoming?.duas) ? incoming!.duas : [];
  const incomingById = new Map(incomingDuas.map((dua) => [dua.id, dua]));

  const mergedBuiltin = defaults.duas.map((builtin) => {
    const saved = incomingById.get(builtin.id);
    const savedActive = typeof saved?.active === 'boolean' ? saved.active : builtin.active;
    return {
      ...builtin,
      active: savedActive,
      isBuiltin: true,
      slots: normalizeSlots(saved?.slots ?? builtin.slots),
      weekdays: normalizeWeekdays(saved?.weekdays ?? builtin.weekdays),
      lineDurationSec: sanitizeDuration(saved?.lineDurationSec) ?? sanitizeDuration(builtin.lineDurationSec)
    };
  });

  const customDuas = incomingDuas
    .filter((dua) => !defaults.duas.some((builtin) => builtin.id === dua.id))
    .map((dua) => ({
      id: dua.id,
      title: (dua.title || '').trim() || 'دعاء جديد',
      text: dua.text || '',
      active: typeof dua.active === 'boolean' ? dua.active : true,
      slots: normalizeSlots(dua.slots),
      weekdays: normalizeWeekdays(dua.weekdays),
      lineDurationSec: sanitizeDuration(dua.lineDurationSec),
      isBuiltin: false
    }));

  const mergedDuas = [...mergedBuiltin, ...customDuas];
  const allIds = new Set(mergedDuas.map((dua) => dua.id));
  const incomingOrder = Array.isArray(incoming?.duaOrder)
    ? incoming!.duaOrder.filter((id) => allIds.has(id))
    : [];
  const remainingIds = mergedDuas.map((dua) => dua.id).filter((id) => !incomingOrder.includes(id));
  const normalizedMinutes = Math.max(1, Math.min(90, Number(incoming?.automation?.minutesBeforePrayer || defaults.automation.minutesBeforePrayer)));
  const normalizedAdvanceMode = incoming?.advanceMode === 'auto' ? 'auto' : defaults.advanceMode;
  const beforePrayerMap = {
    ...defaults.automation.beforePrayerDuaByPrayer,
    ...(incoming?.automation?.beforePrayerDuaByPrayer || {})
  };

  return {
    ...defaults,
    ...(incoming || {}),
    mosqueMode: false,
    hideAdminControlsInMosqueMode: false,
    advanceMode: normalizedAdvanceMode,
    backgroundColor: sanitizeColor(incoming?.backgroundColor, defaults.backgroundColor),
    readingBarColor: sanitizeColor(incoming?.readingBarColor, defaults.readingBarColor),
    showReadingBar: typeof incoming?.showReadingBar === 'boolean' ? incoming.showReadingBar : defaults.showReadingBar,
    automation: {
      ...defaults.automation,
      ...(incoming?.automation || {}),
      minutesBeforePrayer: normalizedMinutes,
      beforePrayerDuaByPrayer: {
        fajr: allIds.has(beforePrayerMap.fajr) ? beforePrayerMap.fajr : defaults.automation.beforePrayerDuaByPrayer.fajr,
        dhuhr: allIds.has(beforePrayerMap.dhuhr) ? beforePrayerMap.dhuhr : defaults.automation.beforePrayerDuaByPrayer.dhuhr,
        maghrib: allIds.has(beforePrayerMap.maghrib) ? beforePrayerMap.maghrib : defaults.automation.beforePrayerDuaByPrayer.maghrib
      }
    },
    duas: mergedDuas,
    duaOrder: [...incomingOrder, ...remainingIds]
  };
};


